ng": "false", "experiences/4/title": "Sales and Marketing Manager", "experiences/5/companyName": "The President by Akaryn", "experiences/5/employmentType": "Full-time", "experiences/5/jobDescription": "As Senior Guest Experience Manager, I took on full responsibilities in the absence of the Assistant Front Office Manager (AFOM), ensuring smooth daily operations. Part of my role involved training staff on standard operating procedures (SOPs) across various positions, including Guest Experience Agent, Guest Service Agent, Service Centre, and Bellman/Driver roles. Additionally, I provided comprehensive training to staff on hospitality industry standards and best practices. I also trained team members on the Visual One (V1) Property Management System (PMS) to streamline hotel operations. Furthermore, I prepared and submitted monthly reports to hotel management, keeping them informed on operational performance and staff development.", "experiences/5/jobEndedOn": "4-2017", "experiences/5/jobLocation": "Laos", "experiences/5/jobStartedOn": "8-2016", "experiences/5/jobStillWorking": "false", "experiences/5/title": "Senior Guest Experience Manager", "experiences/6/companyId": "34323", "experiences/6/companyIndustry": "Hospitality", "experiences/6/companyLink1": "https://www.linkedin.com/company/banyangroup/", "experiences/6/companyName": "Banyan Tree Hotels & Resorts", "experiences/6/companySize": "10001-0", "experiences/6/companyUrn": "urn:li:fsd_company:34323", "experiences/6/companyWebsite": "https://www.groupbanyan.com/", "experiences/6/employmentType": "Full-time", "experiences/6/jobDescription": "As Villa Host at Banyan Tree Hotels & Resorts, I was responsible for recording guest preferences in the database to personalize future stays, maintaining records of exclusive services, and coordinating with housekeeping and engineering teams to ensure all guest villas were clean, fully operational, and ready upon arrival. I greeted guests warmly, assisted with organizing daily